}

void main() {
  TestWidgetsFlutterBinding.ensureInitialized();

  test('match timer expiry stops session and blocks further counting', () async {
    await useSeededMemoryStorage({
      PrefsKeys.isPowerOn: true,
      PrefsKeys.isPaused: false,
